// Twilio WhatsApp inbound is form-encoded; n8n nests it under $json.body. The website funnel
// ALSO POSTs a JSON "seed" here carrying the intake-form fields so this bot can personalize.
const b = $json.body || $json;
function digits(s){ return String(s||'').replace(/^whatsapp:/i,'').replace(/\D/g,''); }
const RESET_HOURS = 6;

const store = $getWorkflowStaticData('global');
store.sessions = store.sessions || {};

// --- SEED PATH: the funnel handing off the web-form context (name/case/preferred date) -------
// This is NOT a Twilio message; it carries seed:true and the lead's phone. Two flavors:
//   - plain (qualify) seed: a fresh web-form submission. Stash it keyed by phone (same digits()
//     key the inbound path uses) and start a FRESH conversation so the bot's first reply is
//     personalized and re-asks nothing the form already captured.
//   - booked seed (booked:true, fired when the lead books via the landing-page slot picker):
//     mark the SAME conversation as booked in place. This is a continuation of the case the
//     qualify seed already started, not a new one, so it does NOT bump convId / reset memory.
const isSeed = (b.seed === true || b.seed === 'true');
if (isSeed) {
  const sphone = digits(b.phone || b.Phone || b.to || b.To);
  const isBookedSeed = (b.booked === true || b.booked === 'true');
  if (sphone) {
    const prev = store.sessions[sphone] || null;
    if (isBookedSeed) {
      // Keep the existing lead context if we have one; fall back to the booked seed's own
      // fields only if somehow no prior (qualify) session exists for this phone yet.
      const lead = (prev && prev.lead) ? prev.lead : {
        name: String(b.name || b.Name || '').trim(),
        caseText: String(b.treatment_interest || b.case_description || b.case || b.details || '').trim(),
        preferredDate: ''
      };
      store.sessions[sphone] = {
        convId: (prev && prev.convId) || 1,
        lastActivity: Date.now(),
        lastSid: (prev && prev.lastSid) || '',
        lastTwiml: (prev && prev.lastTwiml) || '',
        turns: (prev && prev.turns) || 0,
        everGreeted: true, // booked = past intake; never greet them as a brand-new contact
        offered: [],
        awaitingPick: false,
        lead: lead,
        booked: true,
        bookedLabel: String(b.booked_label || b.bookedLabel || '').trim()
      };
    } else {
      const convId = prev ? ((prev.convId || 1) + 1) : 1;
      // greeted on the seed says whether the FUNNEL texts this lead itself (sms channel or the
      // funnel_whatsapp_send opt-in, and not silenced) — if so, its kick-off IS the one greeting.
      // A seed WITHOUT an explicit greeted:false (e.g. an older funnel build still live) is
      // treated as greeted so a stale funnel + new bot can never double-greet; only the current
      // funnel's explicit greeted:false unlocks the bot's own first-turn greeting. Once anyone
      // has greeted this phone the flag sticks — it survives seed resets and idle boundaries.
      const funnelGreeted = !(b.greeted === false || b.greeted === 'false');
      store.sessions[sphone] = {
        convId: convId,
        lastActivity: Date.now(),
        lastSid: '',
        lastTwiml: '',
        turns: 0,
        everGreeted: !!(prev && prev.everGreeted) || funnelGreeted,
        offered: [],
        awaitingPick: false,
        lead: {
          name: String(b.name || b.Name || '').trim(),
          caseText: String(b.treatment_interest || b.case_description || b.case || b.details || '').trim(),
          preferredDate: String(b.preferred_date || b.preferredDate || '').trim()
        },
        booked: false,
        bookedLabel: ''
      };
    }
  }
  return [{ json: { isSeed: true, phone: sphone, sessionKey: sphone + ':seed' } }];
}

// --- NORMAL INBOUND PATH ---------------------------------------------------------------------
const phone = digits(b.From || b.from);
let text = String(b.Body || b.body || '').trim();
if (!text) text = '(the lead sent a non-text message)';
const profileName = String(b.ProfileName || b.profileName || '').trim();
const sid  = String(b.MessageSid || b.SmsMessageSid || b.messageSid || '');

const s = store.sessions[phone] || null;
// Carry the seeded form context (set when the funnel handed off) across every turn.
const seededLead = (s && s.lead) ? s.lead : {};
// Prefer the name the lead typed on the intake form over the WhatsApp profile name.
const name = (seededLead.name && seededLead.name.trim()) ? seededLead.name.trim() : profileName;

// Idempotency — claim this MessageSid at the TOP, before the slow agent/calendar work.
// Twilio retries an inbound precisely because our reply was slow, so the retry arrives
// WHILE the first run is still in flight. By writing lastSid now (with an empty lastTwiml
// meaning "in flight"), the retry is caught here: if the first run has not finished we ack
// with an empty TwiML; once it finishes the terminal node stores the real reply and any
// later retry of the same sid replays it.
if (s && sid && s.lastSid === sid) {
  return [{ json: {
    phone, text, name, sid,
    sessionKey: phone + ':' + (s.convId || 1),
    leadCase: seededLead.caseText || '', preferredDate: seededLead.preferredDate || '',
    isDuplicate: true,
    dedupTwiml: s.lastTwiml || '<Response></Response>'
  } }];
}

// Conversation boundary — a new conversation (fresh agent memory) starts when the last
// activity was long ago, or the lead explicitly resets. Case text is NOT stored here; it
// lives in the agent's window memory keyed by sessionKey.
const nowMs = Date.now();
const gapMs = RESET_HOURS * 3600 * 1000;
const isReset = /^\s*(reset|restart|start over|new request|new appointment)\s*[.!?]*\s*$/i.test(text);
const newConv = !s ? false : (isReset || (s.lastActivity && (nowMs - s.lastActivity) > gapMs));
const convId = !s ? 1 : (newConv ? (s.convId || 1) + 1 : (s.convId || 1));
// "booked" survives an ordinary idle gap — a "thanks" minutes or hours later must still be
// handled as booked — and is cleared ONLY by an explicit reset text, not merely by the idle
// timeout boundary (which still bumps convId / clears offered as before). A genuinely new
// conversation (the lead resetting on purpose) clears it; a stale-but-same conversation does not.
const stillBooked = !!(s && s.booked === true && !isReset);
const bookedLabel = stillBooked ? String(s.bookedLabel || '') : '';

// Greeting policy — the person is greeted at most ONCE, ever, per phone: either by the funnel's
// own kick-off text (the seed carries greeted:true when that path is enabled) or by this bot on
// the FIRST turn of a conversation. The grant is burned the moment it is given, and everGreeted
// sticks in static data, so a seed reset, an idle boundary, or a model hiccup can never produce
// a second greeting. Booked leads are past intake and are never greeted as new contacts.
const turn = newConv ? 1 : (((s && s.turns) || 0) + 1);
const seeded = !!(s && s.lead && (s.lead.name || s.lead.caseText || s.lead.preferredDate));
const allowGreeting = turn === 1 && !stillBooked && !(s && s.everGreeted);

// Claim the sid now (lastTwiml '' = in flight). Preserve offered/awaitingPick within a
// conversation so Build Slots / Route can see what the lead was last shown; clear them on a
// new conversation. PRESERVE the seeded form context (lead) and the booked status on every turn.
store.sessions[phone] = {
  convId: convId,
  lastActivity: nowMs,
  lastSid: sid,
  lastTwiml: '',
  turns: turn,
  everGreeted: allowGreeting ? true : !!(s && s.everGreeted),
  offered: newConv ? [] : (s && Array.isArray(s.offered) ? s.offered : []),
  awaitingPick: newConv ? false : !!(s && s.awaitingPick),
  lead: (s && s.lead) ? s.lead : null,
  booked: stillBooked,
  bookedLabel: bookedLabel
};

return [{ json: {
  phone, text, name, sid, sessionKey: phone + ':' + convId,
  leadCase: seededLead.caseText || '', preferredDate: seededLead.preferredDate || '',
  booked: stillBooked, bookedLabel: bookedLabel,
  turn, seeded, allowGreeting,
  isDuplicate: false, dedupTwiml: '<Response></Response>'
} }];

// The funnel just handed off the web-form context (already stored by Parse Inbound). Acknowledge
// with an empty 200 — no WhatsApp message is owed here; the bot greets the lead, personalized,
// when they actually text. The funnel ignores this body.
return [{ json: { twiml: '<Response></Response>' } }];

const tz = "America/New_York";
const days = 14;
const inb = $('Code: Parse Inbound').item.json;
const now = DateTime.now().setZone(tz);
// Always fetch from now (today stays bookable); extend the far end to cover a future preferred
// day from the form so a lead who wants a date further out actually has openings fetched for it.
let far = now;
if (inb.preferredDate) { const p = DateTime.fromISO(inb.preferredDate, { zone: tz }); if (p.isValid && p.startOf('day') > now) far = p.startOf('day'); }
return [{ json: { timeMin: now.toISO(), timeMax: far.plus({ days }).endOf('day').toISO() } }];

const inb = $('Code: Parse Inbound').item.json;
const tz = "America/New_York";
const startHour = 9;
const endHour = 17;
const duration = 30;
const interval = 30;
const days = 14;
const PER_DAY = 3;   // spread offers across days so the lead can change the day
const TOTAL = 12;    // overall cap — covers ~4+ business days of openings

const store = $getWorkflowStaticData('global');
const sess = (store.sessions && store.sessions[inb.phone]) || {};
const awaitingPick = sess.awaitingPick === true && Array.isArray(sess.offered) && sess.offered.length > 0;

let out;
if (awaitingPick) {
  // The lead is choosing from times we already offered — reuse that EXACT set so the choice
  // maps to the time they saw (no per-turn re-numbering).
  out = sess.offered;
} else {
  // getAll runs with alwaysOutputData, so an empty calendar yields one empty item => no busy
  // events => everything open. Build a set of openings SPANNING days (<=PER_DAY each).
  const events = $input.all().map(i => i.json).filter(Boolean);
  const busy = [];
  for (const ev of events) {
    if (!ev || ev.status === 'cancelled' || ev.transparency === 'transparent') continue;
    const s = ev.start && (ev.start.dateTime || ev.start.date);
    const e = ev.end && (ev.end.dateTime || ev.end.date);
    if (!s || !e) continue;
    busy.push([DateTime.fromISO(s, { zone: tz }), DateTime.fromISO(e, { zone: tz })]);
  }
  const overlaps = (s, e) => busy.some(([bs, be]) => s < be && e > bs);
  const now = DateTime.now().setZone(tz).plus({ minutes: 60 });
  // Honor a preferred date from the form: start the spread on that future day so a lead who
  // asked for a day further out sees THAT day's times first, not just today's.
  let pref = null;
  if (inb.preferredDate) { const p = DateTime.fromISO(inb.preferredDate, { zone: tz }); if (p.isValid && p.startOf('day') > now) pref = p.startOf('day'); }
  out = [];
  let dt = (pref || now).set({ minute: 0, second: 0, millisecond: 0 });
  const limit = dt.plus({ days });
  let curDay = dt.toFormat('yyyy-LL-dd');
  let perDay = 0;
  let guard = 0;
  while (out.length < TOTAL && dt < limit && guard < 12000) {
    guard++;
    const dayKey = dt.toFormat('yyyy-LL-dd');
    if (dayKey !== curDay) { curDay = dayKey; perDay = 0; }
    if (dt.weekday > 5) { dt = dt.plus({ days: 1 }).set({ hour: startHour, minute: 0, second: 0, millisecond: 0 }); continue; }
    if (dt.hour < startHour) { dt = dt.set({ hour: startHour, minute: 0, second: 0, millisecond: 0 }); }
    const dayEnd = dt.set({ hour: endHour, minute: 0, second: 0, millisecond: 0 });
    if (perDay >= PER_DAY || dt.plus({ minutes: duration }) > dayEnd) {
      dt = dt.plus({ days: 1 }).set({ hour: startHour, minute: 0, second: 0, millisecond: 0 });
      continue;
    }
    if (dt < now) { dt = dt.plus({ minutes: interval }); continue; }
    if (!overlaps(dt, dt.plus({ minutes: duration }))) {
      out.push({ iso: dt.toISO(), label: dt.toFormat("cccc, LLL d 'at' h:mm a") });
      perDay++;
    }
    dt = dt.plus({ minutes: interval });
  }
}

const slotsForPrompt = out.length
  ? out.map((s, i) => '[' + (i + 1) + '] ' + s.label).join('\n')
  : '(no open consult times in the next ' + days + ' days, apologize and offer to have the team follow up)';

// Assemble the intake-form context the agent personalizes from (plain text, no n8n braces).
const lc = [];
if (inb.name) lc.push('Name: ' + inb.name);
if (inb.leadCase) lc.push('What they want (their words): ' + inb.leadCase);
if (inb.preferredDate) lc.push('Preferred consult date: ' + inb.preferredDate);
const leadContext = lc.length ? lc.join('\n') : '(no intake form on file, ask what treatment they are interested in)';

// Booked lead — the funnel already booked this person via the landing-page slot picker. Pass a
// plain-language note through to the agent and NEVER show them a times list in this state, so
// there is nothing tempting the agent to re-offer or re-collect.
const booked = inb.booked === true;
const bookedLabel = String(inb.bookedLabel || '').trim();
const bookedContext = booked
  ? ('This person already has a consult booked for ' + (bookedLabel || 'the time they already picked') + '. Do not offer any consult times and do not collect qualifying info.')
  : '';
const finalSlotsForPrompt = booked ? '(the lead already has a consult booked, do not offer any times)' : slotsForPrompt;
const finalAwaitingPick = booked ? false : awaitingPick;

// Opening rule for the agent, decided deterministically upstream (Parse Inbound) so the model
// never has to guess whether this person was already greeted — a funnel kick-off text, an
// earlier turn, or a completed booking all count as greeted.
const allowGreeting = inb.allowGreeting === true;
let greetingRule;
if (booked) {
  greetingRule = 'This person is past intake (their consult is already booked). NEVER open with a greeting. Do not start your reply with Hi, Hey, Hello, or with their name. Answer warmly and directly per the ALREADY BOOKED rules.';
} else if (allowGreeting) {
  greetingRule = 'This is your first reply to this person and nobody from the firm has texted them yet. Open with a short greeting by their first name if you know it (for example "Hi Jose,"), then continue per your rules.';
} else if (inb.seeded && inb.turn === 1) {
  greetingRule = 'This person was ALREADY greeted in an earlier text from the firm, and their latest message may be answering a question the firm already asked them by text. NEVER open with a greeting. Do not start your reply with Hi, Hey, Hello, or with their name. Briefly acknowledge what they just told you, then ask the single most important must-have still missing, or offer consult times if nothing is missing.';
} else {
  greetingRule = 'You are mid-conversation and this person was already greeted. NEVER open with a greeting. Do not start your reply with Hi, Hey, Hello, or with their name. Acknowledge what they just said and continue: the next missing must-have, offering times, or their chosen time, per your other rules.';
}

return [{ json: {
  phone: inb.phone, text: inb.text, name: inb.name, sid: inb.sid, sessionKey: inb.sessionKey,
  slots: out, slotsForPrompt: finalSlotsForPrompt, awaitingPick: finalAwaitingPick, leadContext,
  booked, bookedContext, allowGreeting, greetingRule
} }];

const inb = $('Code: Parse Inbound').item.json;
const built = $('Code: Build Slots').item.json;

// Defensive: the structured parser normally gives an object at $json.output. Fall back to
// parsing a JSON string, or extracting the first JSON object from raw text.
let out = $json.output;
if (typeof out === 'string') { try { out = JSON.parse(out); } catch (e) { out = null; } }
if (!out || typeof out !== 'object') {
  const raw = (typeof $json.output === 'string') ? $json.output : ($json.text || '');
  const m = raw && raw.match(/\{[\s\S]*\}/);
  if (m) { try { out = JSON.parse(m[0]); } catch (e) {} }
}
out = out || {};

const status = String(out.status || 'collecting');
const agentReply = String(out.reply || '').trim();
// Case note for the calendar event: prefer the agent's running summary (form + chat detail),
// fall back to the intake-form case text so the booking always records the person's situation.
const caseSummary = String(out.case_summary || '').trim() || String(inb.leadCase || '').trim();
const slots = Array.isArray(built.slots) ? built.slots : [];
const awaiting = built.awaitingPick === true; // qualified + we already offered times

// Deterministic booked guard — read from Build Slots/Parse Inbound (the session's own record),
// never trust the model alone. Once a lead is booked, NEVER book or offer again no matter what
// status the model returns; a model mistake here must not re-book or re-offer.
const alreadyBooked = built.booked === true || inb.booked === true;

let mode = 'reply', reply = agentReply, chosen_iso = '', chosen_label = '';
let newOffered = [], newAwaiting = false;
const bookedAckReply = "You're all set, I already have you booked in. Reply here anytime if you need to reschedule or have a question before then.";

if (alreadyBooked) {
  reply = agentReply || bookedAckReply;
} else if (status === 'booked') {
  // Defensive fallback: the model reported booked even though our own session record does not.
  // Still never book or offer here, just reply; the session record is what actually decides it.
  reply = agentReply || bookedAckReply;
} else if (status === 'booking' && awaiting) {
  // Map the bracket number against the SAME set the lead was offered (Build Slots pinned
  // built.slots to the stored offered set while awaiting).
  const idx = parseInt(out.chosen_slot_index, 10);
  if (!isNaN(idx) && idx >= 1 && idx <= slots.length) {
    mode = 'book'; chosen_iso = slots[idx - 1].iso; chosen_label = slots[idx - 1].label;
  } else {
    reply = agentReply || "Sorry, which of those times works best for you?";
    newOffered = slots; newAwaiting = slots.length > 0;
  }
} else if (status === 'booking' && !awaiting) {
  // Deterministic gate: never book before we have actually offered times.
  reply = agentReply || "Let's get a couple of details first. What treatment are you interested in?";
} else if (status === 'ready_to_book') {
  // The agent has offered specific times conversationally in its reply; just pin the set.
  reply = agentReply || "You look like a fit! What day and time work best for you?";
  newOffered = slots; newAwaiting = slots.length > 0;
} else if (status === 'declined') {
  reply = agentReply || "Thanks for reaching out, this isn't something we offer.";
} else {
  // collecting. If the lead was mid-pick, PRESERVE the pinned offer so an incidental question
  // (or a non-text message forced to collecting) doesn't drop the times they were shown.
  reply = agentReply || "Could you tell me a bit more about what you're interested in?";
  if (awaiting && slots.length) { newOffered = slots; newAwaiting = true; }
}

// HARD GUARD: greet at most once. When greeting is not allowed on this turn (someone already
// greeted this person, or we are past turn 1), strip any leading salutation the model still
// emitted and re-capitalize what remains. Deterministic — never trusts the model on this.
if (built.allowGreeting !== true && reply) {
  const g = reply.match(/^\s*(hi|hey|hello|hiya|howdy|good\s+(morning|afternoon|evening))\b[^.!?,]{0,40}?[.!?,]+\s*/i);
  if (g) {
    const rest = reply.slice(g[0].length).trim();
    if (rest.length >= 2) reply = rest.charAt(0).toUpperCase() + rest.slice(1);
  }
}

return [{ json: {
  phone: inb.phone, name: inb.name, sid: inb.sid,
  mode, reply, chosen_iso, chosen_label, case_summary: caseSummary,
  offeredJson: JSON.stringify(newOffered), awaitingPick: newAwaiting
} }];

const inb = $('Code: Parse Inbound').item.json;
const r = $('Code: Route').item.json;
const esc = (t) => String(t).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
const twiml = "<Response><Message>" + esc(r.reply || "Thanks, could you tell me a bit more?") + "</Message></Response>";
let offered = [];
try { offered = JSON.parse(r.offeredJson || '[]'); } catch (e) { offered = []; }
const store = $getWorkflowStaticData('global');
store.sessions = store.sessions || {};
store.sessions[inb.phone] = Object.assign({}, store.sessions[inb.phone] || {}, {
  lastSid: inb.sid, lastTwiml: twiml, lastActivity: Date.now(),
  offered: offered, awaitingPick: r.awaitingPick === true
});
return [{ json: { twiml } }];

const r = $('Code: Route').item.json;
const tz = "America/New_York";
const duration = 30;
const parsed = DateTime.fromISO(r.chosen_iso || "", { zone: tz });
const valid = parsed.isValid;
const s = valid ? parsed : DateTime.now().setZone(tz);
const startISO = s.toISO();
const endISO = s.plus({ minutes: duration }).toISO();
return [{ json: { timeMin: startISO, timeMax: endISO, startISO, endISO, human: r.chosen_label || s.toFormat("cccc, LLL d 'at' h:mm a"), valid } }];

const tz = "America/New_York";
const bw = $('Code: Book Window').item.json;
const start = DateTime.fromISO(bw.startISO, { zone: tz });
const end = DateTime.fromISO(bw.endISO, { zone: tz });
const events = $input.all().map(i => i.json).filter(Boolean);
let free = bw.valid !== false && start > DateTime.now().setZone(tz); // must be valid AND in the future
for (const ev of events) {
  if (!ev || ev.status === 'cancelled' || ev.transparency === 'transparent') continue;
  const s = ev.start && (ev.start.dateTime || ev.start.date);
  const e = ev.end && (ev.end.dateTime || ev.end.date);
  if (!s || !e) continue;
  if (start < DateTime.fromISO(e, { zone: tz }) && end > DateTime.fromISO(s, { zone: tz })) { free = false; break; }
}
return [{ json: { free, startISO: bw.startISO, endISO: bw.endISO, human: bw.human } }];

const inb = $('Code: Parse Inbound').item.json;
const vf = $('Code: Verify Free').item.json;
const firm = "Glow Aesthetics Med Spa";
const first = (inb.name || "").trim().split(/\s+/)[0];
const reply = (first ? "Thanks " + first + "! " : "Thanks! ") +
  "Your free consult with " + firm + " is booked for " + vf.human + ". See you then!";
const esc = (t) => String(t).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
const twiml = "<Response><Message>" + esc(reply) + "</Message></Response>";
const store = $getWorkflowStaticData('global');
store.sessions = store.sessions || {};
// Mark this conversation booked (mirrors the funnel's booked-seed path) so a later "thanks"
// after the agent's window memory has rolled off is handled as booked, not re-qualified.
store.sessions[inb.phone] = Object.assign({}, store.sessions[inb.phone] || {}, {
  lastSid: inb.sid, lastTwiml: twiml, lastActivity: Date.now(), offered: [], awaitingPick: false,
  booked: true, bookedLabel: vf.human
});
return [{ json: { twiml } }];

const inb = $('Code: Parse Inbound').item.json;
// The slot the lead picked was taken between the offer and now. Reset so the next message
// pulls fresh availability (we do not re-show the stale set that included the taken slot).
const reply = "Sorry, that time was just taken. Reply with anything and I'll pull fresh times.";
const esc = (t) => String(t).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
const twiml = "<Response><Message>" + esc(reply) + "</Message></Response>";
const store = $getWorkflowStaticData('global');
store.sessions = store.sessions || {};
store.sessions[inb.phone] = Object.assign({}, store.sessions[inb.phone] || {}, {
  lastSid: inb.sid, lastTwiml: twiml, lastActivity: Date.now(), offered: [], awaitingPick: false
});
return [{ json: { twiml } }];
